CREATE TABLE IF NOT EXISTS public.sections (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), project_id uuid NOT NULL REFERENCES public.projects(id) ON DELETE CASCADE, name text NOT NULL, position integer NOT NULL DEFAULT 0, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now()); ALTER TABLE public.sections ENABLE ROW LEVEL SECURITY; CREATE POLICY view_own_sections ON public.sections FOR SELECT USING (EXISTS (SELECT 1 FROM public.projects p WHERE p.id = sections.project_id AND p.user_id = auth.uid())); CREATE POLICY insert_own_sections ON public.sections FOR INSERT WITH CHECK (EXISTS (SELECT 1 FROM public.projects p WHERE p.id = sections.project_id AND p.user_id = auth.uid())); CREATE POLICY update_own_sections ON public.sections FOR UPDATE USING (EXISTS (SELECT 1 FROM public.projects p WHERE p.id = sections.project_id AND p.user_id = auth.uid())); CREATE POLICY delete_own_sections ON public.sections FOR DELETE USING (EXISTS (SELECT 1 FROM public.projects p WHERE p.id = sections.project_id AND p.user_id = auth.uid())); CREATE TRIGGER update_sections_updated_at BEFORE UPDATE ON public.sections FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column(); ALTER TABLE public.tasks ADD CONSTRAINT tasks_section_id_fkey FOREIGN KEY (section_id) REFERENCES public.sections(id) ON DELETE SET NULL; CREATE INDEX IF NOT EXISTS idx_tasks_section_id ON public.tasks(section_id); CREATE INDEX IF NOT EXISTS idx_sections_project_position ON public.sections(project_id, position);